const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

app.disable('x-powered-by');           // hide Express fingerprint
app.use(helmet());                     // sensible default headers (CSP, HSTS, etc.)
app.use(rateLimit({ windowMs: 60_000, max: 100 })); // blunt DoS/brute-force
```

## 6. CORS not explicitly configured
Decide deliberately. If the API is browser-facing, use `cors` with an allowlist rather than `*`:
